(function () {
  'use strict';

  // Source files generated by gen-web are now ``data_<source>_<slug>.js`` so
  // multiple regions can coexist on the same web bundle. Pages no longer
  // bake the data in via ``<script src="data_<source>.js">`` — they ask
  // RegionData.loadOne / loadAll to fetch the right file for whatever
  // region is currently active.
  //
  // The active slug lives in localStorage (key ``rentmap.region.v1``) so
  // the region selector (phase 5) sets it once and every tab on this
  // origin sees the same value. Missing/garbled storage falls back to the
  // legacy "ajou" so a fresh user with no selection still renders the
  // historical default region.

  var STORAGE_KEY = 'rentmap.region.v1';
  var FALLBACK_SLUG = 'ajou';

  function currentSlug() {
    var raw;
    try {
      raw = localStorage.getItem(STORAGE_KEY) || FALLBACK_SLUG;
    } catch (_e) {
      // localStorage can throw in iframes / strict cookie modes; default
      // out without exploding the page.
      raw = FALLBACK_SLUG;
    }
    // Filter to the same charset the server's _SLUG_RE allows so a tampered
    // storage value can't be used to coerce the script src into an arbitrary
    // path (the static mount only serves /web anyway, but defense in depth).
    var cleaned = String(raw).toLowerCase().replace(/[^a-z0-9_-]/g, '');
    return cleaned || FALLBACK_SLUG;
  }

  function setSlug(slug) {
    var cleaned = String(slug || '').toLowerCase().replace(/[^a-z0-9_-]/g, '');
    if (!cleaned) return false;
    try {
      localStorage.setItem(STORAGE_KEY, cleaned);
    } catch (_e) {
      return false;
    }
    return true;
  }

  function globalKey(source) {
    return 'DATA_' + String(source).toUpperCase();
  }

  // Cache-bust on every load so a fresh gen-web shows up without the user
  // needing to hard-refresh. The penalty (one extra round-trip per page
  // boot) is negligible compared to the confusion of stale data.
  function buildSrc(source) {
    return 'data_' + source + '_' + currentSlug() + '.js?v=' + Date.now();
  }

  function loadOne(source, callback) {
    var key = globalKey(source);
    // If a previous loadOne in this page already populated the global
    // (e.g. from the same source on a multi-source page), reuse it.
    if (Array.isArray(window[key])) {
      callback(window[key]);
      return;
    }
    var s = document.createElement('script');
    s.src = buildSrc(source);
    s.async = false;
    s.onload = function () {
      // The data_<source>_<slug>.js file sets window.DATA_<SOURCE>; if it
      // didn't (e.g. empty CSV → empty array still set, we hope), fall
      // back to [].
      callback(Array.isArray(window[key]) ? window[key] : []);
    };
    s.onerror = function () {
      console.warn('RegionData: missing data file', s.src);
      window[key] = [];
      callback([]);
    };
    document.head.appendChild(s);
  }

  function loadAll(sources, callback) {
    var pending = sources.length;
    var results = {};
    if (pending === 0) {
      callback(results);
      return;
    }
    sources.forEach(function (src) {
      loadOne(src, function (rows) {
        results[src] = rows;
        pending -= 1;
        if (pending === 0) callback(results);
      });
    });
  }

  // Favorites needs to look up listing metadata for *any* region the user
  // ever favourited from, not just the active region's. ``loadAllRegions``
  // hits /api/regions for the approved list, then sequentially loads each
  // region's data files and concatenates them into ``window.DATA_<SOURCE>``.
  //
  // Sequential (not parallel) because every data_<source>_<slug>.js file
  // reassigns the same ``window.DATA_<SOURCE>`` global — running them in
  // parallel would race and the last writer wins, throwing away the earlier
  // regions' rows. Serial loads let us capture each contribution before the
  // next script overwrites the global. Cost is N*S round-trips serial; in
  // practice N=1–few and the 4 sources are still fetched in parallel within
  // each region, so total time is roughly N * single-region load time.
  function loadAllRegions(sources, callback) {
    fetch('/api/regions', { credentials: 'same-origin', cache: 'no-store' })
      .then(function (r) { return r.ok ? r.json() : { regions: [] }; })
      .then(function (payload) {
        var slugs = ((payload && payload.regions) || []).map(function (r) { return r.slug; });
        if (!slugs.length) slugs = [currentSlug()];
        var merged = {};
        sources.forEach(function (s) { merged[s] = []; });

        function loadRegion(i) {
          if (i >= slugs.length) {
            // Replace globals with the union so existing listing-data-source
            // / favorites lookups (which already key off DATA_<SOURCE>)
            // transparently see every region's rows.
            sources.forEach(function (s) {
              window[globalKey(s)] = merged[s];
            });
            callback(merged);
            return;
          }
          var slug = slugs[i];
          var pending = sources.length;
          sources.forEach(function (source) {
            var key = globalKey(source);
            // Null the global before each load so we only capture what this
            // particular script contributes, not whatever the prior region
            // left behind.
            window[key] = null;
            var s = document.createElement('script');
            s.src = 'data_' + source + '_' + slug + '.js?v=' + Date.now();
            s.onload = function () {
              if (Array.isArray(window[key])) {
                merged[source] = merged[source].concat(window[key]);
              }
              pending -= 1;
              if (pending === 0) loadRegion(i + 1);
            };
            s.onerror = function () {
              // Missing data file for a region = that region just hasn't
              // crawled yet. Not an error — keep going.
              pending -= 1;
              if (pending === 0) loadRegion(i + 1);
            };
            document.head.appendChild(s);
          });
        }
        loadRegion(0);
      })
      .catch(function (err) {
        // /api/regions failed (likely 401 / network blip). Fall back to
        // the single-region path so the page still renders something.
        console.warn('RegionData.loadAllRegions: falling back to single region', err);
        loadAll(sources, callback);
      });
  }

  window.RegionData = {
    STORAGE_KEY: STORAGE_KEY,
    currentSlug: currentSlug,
    setSlug: setSlug,
    loadOne: loadOne,
    loadAll: loadAll,
    loadAllRegions: loadAllRegions,
  };
})();
